CREATE PROCEDURE csr_test()
{
declare kname, cvalue varchar;
declare _key any;
declare _output int;
 xenc_key_RSA_create ('RSAKey2', 2048);
 _key := xenc_x509_csr_generate ('RSAKey2',
  vector ('CN', 'Test user', 'C', 'US', 'O', 'OpenLink', 'OU', 'Testing', 'emailAddress', 'test@openlinksw.com'),
  vector ('subjectAltName', 'DNS:test.openlinksw.com', 'nsComment', 'Virtuoso Certificate for Testing', 'authorityKeyIdentifier', 'keyid,issuer:always'));
 xenc_x509_from_csr ('id_rsa', 'TestKey', _key, sequence_next('ca_id_rsa'), 365, 100);
 return xenc_pem_export ('TestKey');
}
;

CREATE PROCEDURE csr_complex()
{
declare kname, cvalue varchar;
declare _key any;
declare _output int;
 xenc_key_RSA_create ('RSAKey3', 4096);
 _key := xenc_x509_csr_generate ('RSAKey3',
  vector ('CN', 'Complex user', 'C', 'US', 'O', 'OpenLink', 'OU', 'Complex Tests', 'emailAddress', 'complex@openlinksw.com'),
  vector ('subjectAltName', 'DNS:complex.openlinksw.com', 'URI:http://www.openlinksw.com/complex', 'nsComment', 'Complex Certificate', 'authorityKeyIdentifier', 'keyid,issuer:always'));
 xenc_x509_from_csr ('id_rsa', 'ComplexKey', _key, (SELECT sequence_next('ca_id_rsa') FROM cert_requests WHERE id = 1), 730, 50);
 return xenc_pem_export ('ComplexKey');
};

